const ctx = require('./.forge/project-context.json');
// Required: project.name and project.prefix must be non-empty strings
if (!ctx.project || typeof ctx.project.name !== 'string' || ctx.project.name.trim() === '') {
  console.error('✗ Phase 2 validation failed: project.name is missing or empty.');
  process.exit(1);
}
if (!ctx.project || typeof ctx.project.prefix !== 'string' || ctx.project.prefix.trim() === '') {
  console.error('✗ Phase 2 validation failed: project.prefix is missing or empty.');
  process.exit(1);
}
// All array fields must be arrays
const arrayFields = [
  ['project.stack', ctx.project.stack],
  ['architecture.keyDirectories', ctx.architecture.keyDirectories],
  ['entities', ctx.entities],
  ['impactCategories', ctx.impactCategories],
  ['technicalDebt', ctx.technicalDebt],
  ['deployment.environments', ctx.deployment.environments],
  ['skillWiring', ctx.skillWiring]
];
for (const [name, val] of arrayFields) {
  if (!Array.isArray(val)) {
    console.error('✗ Phase 2 validation failed: ' + name + ' is not an array.');
    process.exit(1);
  }
}
console.log('✓ project-context.json validation passed');
"

